async function decode(e,o){const n=new AudioContext({sampleRate:o}),t=n.decodeAudioData(e);return t.finally(()=>n.close())}function normalize(e){const n=e[0];if(n.some(e=>1<e||e<-1)){var t=n.length;let o=0;for(let e=0;e<t;e++){var r=Math.abs(n[e]);r>o&&(o=r)}for(const a of e)for(let e=0;e<t;e++)a[e]/=o}return e}function createBuffer(o,e){return normalize(o="number"==typeof o[0]?[o]:o),{duration:e,length:o[0].length,sampleRate:o[0].length/e,numberOfChannels:o.length,getChannelData:e=>o?.[e],copyFromChannel:AudioBuffer.prototype.copyFromChannel,copyToChannel:AudioBuffer.prototype.copyToChannel}}const Decoder={decode:decode,createBuffer:createBuffer};export default Decoder;